const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'REDACTED_SUPABASE_KEY';
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';
let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
try {
  const rows = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email)&select=key,value&user_id=eq.${encodeURIComponent(userId)}`,
    headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
  });
  for (const row of rows) {
    if (row.key === 'recipient_email' && !recipient_email) recipient_email = row.value;
    if (row.key === 'bcc_email' && !bcc_email) bcc_email = row.value;
  }
} catch (e) {
  if (!recipient_email) recipient_email = 'eric@agileadtesting.com';
}
return [{ json: { SUPABASE_URL, SUPABASE_API_KEY, userId, recipient_email, bcc_email: bcc_email || '', page_size: trigger.page_size || '6x9', project_title: trigger.project_title || '', user_prompt: trigger.user_prompt || '' } }];

const settings = $('settings').first().json;
const SB = settings.SUPABASE_URL;
const AK = settings.SUPABASE_API_KEY;
const hd = { 'apikey': AK, 'Authorization': 'Bearer ' + AK };
const uf = settings.userId ? '&user_id=eq.' + encodeURIComponent(settings.userId) : '';

const pr = await this.helpers.httpRequest({
  method: 'GET',
  url: SB + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(settings.project_title) + '*&select=id,title,genre_slug&limit=1' + uf,
  headers: hd
});
const project = Array.isArray(pr) && pr.length > 0 ? pr[0] : null;
if (!project) {
  return [{ json: { error: true, result: 'Project not found: ' + settings.project_title } }];
}

let chapters = await this.helpers.httpRequest({
  method: 'GET',
  url: SB + '/rest/v1/published_content_v2?project_id=eq.' + project.id + '&content_type=eq.chapter&order=chapter_number.asc&select=id,title,chapter_number,content_text,storage_path' + uf,
  headers: hd
});
chapters = Array.isArray(chapters) ? chapters : [];

if (chapters.length === 0 && project.genre_slug) {
  const fb = await this.helpers.httpRequest({
    method: 'GET',
    url: SB + '/rest/v1/published_content_v2?content_type=eq.chapter&genre_slug=eq.' + encodeURIComponent(project.genre_slug) + '&order=chapter_number.asc&select=id,title,chapter_number,content_text,storage_path&limit=100' + uf,
    headers: hd
  });
  chapters = Array.isArray(fb) ? fb : [];
}
if (chapters.length === 0) {
  return [{ json: { error: true, result: 'No chapters found for "' + project.title + '". Write and approve some chapters first.' } }];
}

for (const c of chapters) {
  if (!c.content_text && c.storage_path) {
    try {
      const raw = await this.helpers.httpRequest({
        method: 'GET',
        url: SB + '/storage/v1/object/' + c.storage_path,
        headers: hd
      });
      c.content_text = typeof raw === 'string' ? raw : JSON.stringify(raw);
    } catch (e) {
      c.content_text = '';
    }
  }
}

return [{
  json: {
    error: false,
    project_title: project.title,
    project_id: project.id,
    chapters_count: chapters.length,
    page_size: settings.page_size || '6x9',
    doc_title: project.title + ' - KDP Manuscript',
    chapters: chapters
  }
}];

const prev = $('build_kindle_manuscript').first().json;
const chapters = prev.chapters;
const projectTitle = prev.project_title;

function chapterLabel(c) {
  const cn = parseInt(c.chapter_number);
  const titleLower = (c.title || '').toLowerCase();
  if (cn === 0 || titleLower.indexOf('prologue') >= 0) return 'Prologue - ' + (c.title || 'Prologue');
  if (cn === 999 || titleLower.indexOf('epilogue') >= 0) return 'Epilogue - ' + (c.title || 'Epilogue');
  return 'Chapter ' + cn + ': ' + (c.title || '');
}

function stripHtml(html) {
  if (!html) return '';
  let text = html;
  text = text.replace(/<\/(p|div|h[1-6]|blockquote|li|tr)>/gi, '\n\n');
  text = text.replace(/<br\s*\/?>/gi, '\n');
  text = text.replace(/<hr\s*\/?>/gi, '\n\n* * *\n\n');
  text = text.replace(/<[^>]+>/g, '');
  text = text.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>');
  text = text.replace(/&quot;/g, '"').replace(/&#39;/g, "'");
  text = text.replace(/&mdash;/g, '\u2014').replace(/&ndash;/g, '\u2013');
  text = text.replace(/&ldquo;/g, '\u201C').replace(/&rdquo;/g, '\u201D');
  text = text.replace(/&lsquo;/g, '\u2018').replace(/&rsquo;/g, '\u2019');
  text = text.replace(/&hellip;/g, '\u2026').replace(/&nbsp;/g, ' ');
  text = text.replace(/&#(\d+);/g, function(m, c) { return String.fromCharCode(parseInt(c)); });
  text = text.replace(/\n{3,}/g, '\n\n');
  return text.trim();
}

const midpoint = Math.ceil(chapters.length / 2);
const parts = [chapters.slice(0, midpoint), chapters.slice(midpoint)];
const results = [];

for (let p = 0; p < parts.length; p++) {
  const partChapters = parts[p];
  if (partChapters.length === 0) continue;
  const partNum = p + 1;
  let fullText = '\n\n\n' + projectTitle + '\n\n\n\n';
  for (let i = 0; i < partChapters.length; i++) {
    const c = partChapters[i];
    const label = chapterLabel(c);
    const content = stripHtml(c.content_text || '');
    if (i > 0) fullText += '\n\n\n';
    fullText += label + '\n\n';
    if (content) fullText += content + '\n';
  }
  const insertRequestBody = JSON.stringify({
    requests: [{ insertText: { text: fullText, endOfSegmentLocation: {} } }]
  });
  const firstCh = partChapters[0];
  const lastCh = partChapters[partChapters.length - 1];
  const fn = parseInt(firstCh.chapter_number);
  const ln = parseInt(lastCh.chapter_number);
  const fl = (fn === 0) ? 'Prologue' : (fn === 999) ? 'Epilogue' : 'Ch ' + fn;
  const ll = (ln === 0) ? 'Prologue' : (ln === 999) ? 'Epilogue' : 'Ch ' + ln;
  results.push({
    json: {
      part: partNum, project_title: projectTitle, chapters_count: partChapters.length,
      page_size: prev.page_size || '6x9',
      doc_title: projectTitle + ' - Part ' + partNum + ' (' + fl + ' to ' + ll + ')',
      textContent: fullText, insertRequestBody: insertRequestBody, chapters: partChapters
    }
  });
}

return results;

const items = $input.all();
const buildTextItems = $('build_text').all();
const results = [];

for (let idx = 0; idx < items.length; idx++) {
  const doc = items[idx].json;
  const bt = buildTextItems[idx].json;
  const bodyContent = doc.body.content;
  const projectTitle = bt.project_title;
  const chapters = bt.chapters;

  function chapterLabel(c) {
    const cn = parseInt(c.chapter_number);
    const titleLower = (c.title || '').toLowerCase();
    if (cn === 0 || titleLower.indexOf('prologue') >= 0) return 'Prologue - ' + (c.title || 'Prologue');
    if (cn === 999 || titleLower.indexOf('epilogue') >= 0) return 'Epilogue - ' + (c.title || 'Epilogue');
    return 'Chapter ' + cn + ': ' + (c.title || '');
  }

  const expectedHeadings = [{ text: projectTitle, style: 'TITLE' }];
  for (const c of chapters) {
    expectedHeadings.push({ text: chapterLabel(c), style: 'HEADING_1' });
  }

  const foundHeadings = [];
  for (const element of bodyContent) {
    if (!element.paragraph) continue;
    const para = element.paragraph;
    let paraText = '';
    for (const el of (para.elements || [])) {
      if (el.textRun && el.textRun.content) paraText += el.textRun.content;
    }
    const trimmedText = paraText.replace(/\n/g, '').trim();
    if (!trimmedText) continue;

    if (trimmedText.charAt(0) === '#' && trimmedText.charAt(1) === ' ') {
      foundHeadings.push({
        startIndex: element.startIndex,
        endIndex: element.endIndex - 1,
        style: 'HEADING_2',
        isSubchapter: true
      });
      continue;
    }

    for (const h of expectedHeadings) {
      if (trimmedText === h.text) {
        foundHeadings.push({
          startIndex: element.startIndex,
          endIndex: element.endIndex - 1,
          style: h.style,
          isSubchapter: false
        });
        break;
      }
    }
  }

  // Style requests for all headings
  const styleReqs = [];
  for (const h of foundHeadings) {
    styleReqs.push({
      updateParagraphStyle: {
        range: { startIndex: h.startIndex, endIndex: h.endIndex },
        paragraphStyle: {
          namedStyleType: h.style,
          alignment: (h.style === 'TITLE' || h.style === 'HEADING_1') ? 'CENTER' : 'START'
        },
        fields: 'namedStyleType,alignment'
      }
    });
  }

  // Combine page breaks (HEADING_1 only) and # deletions (HEADING_2)
  // Both sorted by descending startIndex so shifts don't conflict
  const modReqs = [];
  for (const h of foundHeadings) {
    if (h.style === 'HEADING_1') {
      modReqs.push({ startIndex: h.startIndex, type: 'pageBreak' });
    }
    if (h.isSubchapter) {
      modReqs.push({ startIndex: h.startIndex, type: 'deleteHash' });
    }
  }
  modReqs.sort(function(a, b) { return b.startIndex - a.startIndex; });

  const pbAndDelReqs = [];
  for (const m of modReqs) {
    if (m.type === 'pageBreak') {
      pbAndDelReqs.push({ insertPageBreak: { location: { index: m.startIndex } } });
    } else {
      pbAndDelReqs.push({ deleteContentRange: { range: { startIndex: m.startIndex, endIndex: m.startIndex + 2 } } });
    }
  }

  results.push({
    json: {
      documentId: doc.documentId, project_title: bt.project_title, part: bt.part,
      doc_title: bt.doc_title, chapters_count: bt.chapters_count, page_size: bt.page_size,
      headingsFound: foundHeadings.length,
      styleRequestsBody: JSON.stringify({ requests: styleReqs }),
      pageBreakRequestsBody: JSON.stringify({ requests: pbAndDelReqs })
    }
  });
}

return results;

const fhItems = $('find_headings').all();
const btItems = $('build_text').all();
const settings = $('settings').first().json;
const docs = [];
for (let i = 0; i < fhItems.length; i++) {
  docs.push({
    documentId: fhItems[i].json.documentId,
    doc_title: fhItems[i].json.doc_title || btItems[i].json.doc_title,
    chapters_count: fhItems[i].json.chapters_count,
    part: fhItems[i].json.part
  });
}
return [{
  json: {
    project_title: fhItems[0].json.project_title,
    page_size: fhItems[0].json.page_size,
    docs: docs,
    total_chapters: docs.reduce(function(sum, d) { return sum + d.chapters_count; }, 0),
    recipient_email: settings.recipient_email,
    bcc_email: settings.bcc_email,
    user_prompt: settings.user_prompt
  }
}];

const items = $input.all();

for (const item of items) {
  const docTitle = item.json.doc_title;
  const query = "name='" + docTitle.replace(/'/g, "\\'") + "' and mimeType='application/vnd.google-apps.document' and trashed=false";
  const searchUrl = 'https://www.googleapis.com/drive/v3/files?q=' + encodeURIComponent(query) + '&fields=files(id,name)';
  try {
    const searchResult = await this.helpers.httpRequestWithAuthentication.call(this, 'googleDriveOAuth2Api', {
      method: 'GET',
      url: searchUrl,
      json: true
    });
    if (searchResult.files && searchResult.files.length > 0) {
      for (const file of searchResult.files) {
        try {
          await this.helpers.httpRequestWithAuthentication.call(this, 'googleDriveOAuth2Api', {
            method: 'DELETE',
            url: 'https://www.googleapis.com/drive/v3/files/' + file.id
          });
        } catch (delErr) {
          // ignore delete errors
        }
      }
    }
  } catch (e) {
    // ignore search errors - proceed with creation
  }
}

return items;
